SELECT [giac-02-AssortimentiInGiacenza-step02].[Model Item No_] AS Article, [giac-02-AssortimentiInGiacenza-step02].[Constant Variable Code] AS Color, [giac-02-AssortimentiInGiacenza-step02].[Assortment Code] AS Assortment, [giac-02-AssortimentiInGiacenza-step02].AssortimentiInGiacenza, [giac-01-AssortimentiInBolla-step02].AssortimentiInBolla, [AssortimentiInGiacenza]-nz([AssortimentiInBolla]) AS AssortimentiLiberi, [Variable Code].Description AS ColorDescription, [AssortimentiInGiacenza]*[PaiaPerAssortimento] AS PaiaiInGiacenza, [AssortimentiInBolla]*[PaiaPerAssortimento] AS PaiaInBolla, [AssortimentiLiberi]*[PaiaPerAssortimento] AS PaiaLibere
FROM (([giac-01-AssortimentiInBolla-step02] RIGHT JOIN [giac-02-AssortimentiInGiacenza-step02] ON ([giac-01-AssortimentiInBolla-step02].[Constant Variable Code] = [giac-02-AssortimentiInGiacenza-step02].[Constant Variable Code]) AND ([giac-01-AssortimentiInBolla-step02].[Assortment Code] = [giac-02-AssortimentiInGiacenza-step02].[Assortment Code]) AND ([giac-01-AssortimentiInBolla-step02].No_ = [giac-02-AssortimentiInGiacenza-step02].[Model Item No_])) LEFT JOIN [Variable Code] ON ([giac-02-AssortimentiInGiacenza-step02].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([giac-02-AssortimentiInGiacenza-step02].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])) LEFT JOIN [giac-02-CalcoloPaiassortimenti] ON ([giac-02-AssortimentiInGiacenza-step02].[Assortment Code] = [giac-02-CalcoloPaiassortimenti].[Assortment Code]) AND ([giac-02-AssortimentiInGiacenza-step02].[Assortment Variable Group] = [giac-02-CalcoloPaiassortimenti].[Variable Group]);

